import{_ as e,o as t,c as r,am as i}from"./chunks/framework.foOaJFbm.js";const f=JSON.parse('{"title":"About T_TIDE","description":"","frontmatter":{"title":"About T_TIDE","description":"","navbar":true,"sideBar":true,"footer":true,"outline":[1,3],"editLink":true,"lastUpdated":true,"aside":"right","layout":"doc","custom":{},"hero":{"image":{"src":"","alt":"","width":"","height":""},"name":"VitePressSimple","text":"quick to config vitePress","description":"","tagline":"","actions":[],"features":[],"head":[]}},"headers":[],"relativePath":"about/index.md","filePath":"about/index.md","lastUpdated":1772429025000}'),n={name:"about/index.md"};function o(s,a,l,d,h,c){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="about-s-tide" tabindex="-1">About S_TIDE <a class="header-anchor" href="#about-s-tide" aria-label="Permalink to “About S_TIDE”">​</a></h1><p>S_TIDE is developed by <a href="https://www.researchgate.net/profile/Haidong-Pan" target="_blank" rel="noreferrer">Dr. Haidong Pan</a> based on <a href="https://www-old.eoas.ubc.ca/~rich/" target="_blank" rel="noreferrer">T_Tide</a>. S_TIDE is still being continuously updated, with the goal of making it an all-in-one toolbox for tidal data. Namely, I wish that everything about tides can be handled via S_TIDE.</p><p>S_TIDE toolbox also contains a Graphical User Interface (GUI) which can perform harmonic analysis, predict tides and calculate riding tidal levels. This GUI is designed for users who are not familiar with MATLAB programming.</p><h1 id="citation" tabindex="-1">Citation <a class="header-anchor" href="#citation" aria-label="Permalink to “Citation”">​</a></h1><p>Please refer Pan et al., (2018) if you use S_TIDE in your paper!</p><p>Pan, H., Lv, X., Wang, Y., Matte, P., Chen, H., Jin, G., 2018. Exploration of Tidal-Fluvial Interaction in the Columbia River Estuary Using S_TIDE. J. Geophys. Res. Oceans 123, 6598–6619. <a href="https://doi.org/10.1029/2018JC014146" target="_blank" rel="noreferrer">https://doi.org/10.1029/2018JC014146</a></p><h1 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to “Contact”">​</a></h1><p>If you have any questions, just send emails to Dr. Pan (<a href="mailto:panhaidong@fio.org.cn" target="_blank" rel="noreferrer">panhaidong@fio.org.cn</a>, or <a href="mailto:panhaidong_phd@qq.com" target="_blank" rel="noreferrer">panhaidong_phd@qq.com</a>).</p><h1 id="acknowledgements" tabindex="-1">Acknowledgements <a class="header-anchor" href="#acknowledgements" aria-label="Permalink to “Acknowledgements”">​</a></h1><p>I appreciate <a href="https://www.eoas.ubc.ca/people/richpawlowicz" target="_blank" rel="noreferrer">Prof. Rich Pawlowicz</a> for developing the <a href="https://www-old.eoas.ubc.ca/~rich/" target="_blank" rel="noreferrer">T_Tide</a> package, which is the basis of S_TIDE. I also thank <a href="https://jia-shun.wang" target="_blank" rel="noreferrer">Jiashun Wang</a> for creating and maintaining this website.</p>',10)])])}const g=e(n,[["render",o]]);export{f as __pageData,g as default};
